#!/usr/bin/env python3
"""
2차전지 & EV 탭 데이터를 fields.js / analysis.js에 패치.
GitHub Actions 빌드 시 npm run build 전에 실행.
"""
import gzip, base64, re

FIELDS_DATA = ""
ANALYSIS_DATA = ""

def decompress(data):
    return gzip.decompress(base64.b64decode(data)).decode('utf-8')

fields_path = 'src/data/fields.js'
with open(fields_path, 'r', encoding='utf-8') as f:
    txt = f.read()

if 'battery:' not in txt:
    battery_block = decompress(FIELDS_DATA)
    txt = txt.replace('  quantum:{', battery_block + '\n  quantum:{', 1)
    with open(fields_path, 'w', encoding='utf-8') as f:
        f.write(txt)
    print('fields.js: battery 탭 삽입 완료')
else:
    print('fields.js: battery 탭 이미 존재, 스킵')

analysis_path = 'src/data/analysis.js'
with open(analysis_path, 'r', encoding='utf-8') as f:
    atxt = f.read()

if '"ALB"' not in atxt:
    battery_entries = decompress(ANALYSIS_DATA)
    atxt = re.sub(r'\n};\s*$', '\n  ' + battery_entries + ',\n};\n', atxt)
    with open(analysis_path, 'w', encoding='utf-8') as f:
        f.write(atxt)
    print('analysis.js: 배터리 종목 분석 삽입 완료')
else:
    print('analysis.js: 배터리 데이터 이미 존재, 스킵')

print('패치 완료')
